import React, { useEffect, useState } from 'react';
import { Container, AppBar, Typography, Grow, Grid } from '@material-ui/core';
import Form from './components/Form/Form.js';
import Posts from './components/Posts/Posts.js';
import { useDispatch } from 'react-redux';
import { getPosts } from './actions/posts.js';

import useStyles from './styles';
import instaJam from './images/instaJam.jpg';


function App() {
  const [currentId, setCurrentId] = useState(null);
  const classes = useStyles();
  const dispatch = useDispatch();

  useEffect(() => {
    dispatch(getPosts());
  }, [currentId, dispatch]);

  return (
    <Container maxwidth='lg'>
      <AppBar className={classes.appBar} position='static' color='inherit'>
        <Typography className={classes.heading} variant='h2' align='center'>instaJam</Typography>
        <img className={classes.image} src={instaJam} alt='instaJam' height='60'/>
      </AppBar>
      <Grow in>
        <Container>
          <Grid container directon='column-reverse' justifyContent="space-between" alignItems='stretch' spacing={3}>
            <Grid item xs={12} sm={7}>
              <Posts setCurrentId={setCurrentId}/>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Form currentId={currentId} setCurrentId={setCurrentId}/>
            </Grid>
          </Grid>
        </Container>
      </Grow>
    </Container>
  );
}

export default App;
